# Calculate effective max demand charges
def calc_max_flat(seasons):
    max_charge = 0
    for s in seasons:
        base = s.get("base", 0)
        adj = s.get("adj", 0)
        # The first tier (max 5 or 10 kW) is free, so the highest paid rate is base + adj
        total = base + adj
        if total > max_charge:
            max_charge = total
    return max_charge

def calc_max_tod(r):
    # For TOD, we need to compare base + adj across all periods
    # The maximum would be the highest sum of base + adjustment in any period
    max_charge = 0
    if "tod" in r:
        for period in r["tod"]:
            total = period.get("rate", 0) + period.get("adj", 0)
            if total > max_charge:
                max_charge = total
    return max_charge

