    for s in r.get("seasons", []):
        total = s.get("base", 0) + s.get("adj", 0)
        if total > max_seasonal:
            max_seasonal = total

    overall_max = max(max_flat, max_tod, max_seasonal)
    results.append({"name": r["name"], "max_demand_charge": overall_max})

results_sorted = sorted(results, key=lambda x: x["max_demand_charge"], reverse=True)
for i, r in enumerate(results_sorted[:10]):
